export const getGetPerformanceMetricsUrl = (params?: GetPerformanceMetricsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/dashboard/performance?${stringifiedParams}` : `/api/dashboard/performance`
}

/**
 * @summary Get performance metrics over time
 */
